// 把 App 傳來的演練紀錄整理成 Apps Script 期待的欄位（鍵名需與 google-apps-script.gs 的 HEADERS 一致）
const b = $input.first().json.body || $input.first().json;
const join = (a) => Array.isArray(a) ? a.join('、') : (a || '');

// ISO 時間 → 台灣時區好讀格式（2026/07/16 15:00）
let when = b.date || '';
if (when) {
  const d = new Date(when);
  if (!isNaN(d)) {
    when = d.toLocaleString('zh-TW', {
      timeZone: 'Asia/Taipei',
      year: 'numeric', month: '2-digit', day: '2-digit',
      hour: '2-digit', minute: '2-digit', hour12: false
    }).replace(/-/g, '/');
  }
}

const transcript = Array.isArray(b.transcript)
  ? b.transcript.map(t => `${t.role === 'sales' ? '業務' : '店長'}：${t.text}`).join('\n')
  : '';

const cs = Array.isArray(b.construct_scores)
  ? b.construct_scores.map(c => `${c.name}:${c.mark}${c.score != null ? c.score : ''}`).join('、')
  : '';

return [{ json: {
  '時間': when,
  '業務': b.name || '',
  '主題': b.theme || '',
  '模式': b.mode || '',
  '總分': (b.total_score != null ? b.total_score : ''),
  '層級': b.level || '',
  '層級說明': b.level_note || '',
  '待加強面向': join(b.weak_areas),
  '各面向分數': cs,
  '逐字稿': transcript
} }];
